commands.cmd:
set --
[ -n '' ] && set -- "$@" --context ''
if [ -n '' ]; then
  kubectl get namespace '' "$@" >/dev/null || { echo "namespace not found or not readable" >&2; exit 1; }
  set -- "$@" -n ''
else
  set -- "$@" -A
fi
pods=$(kubectl get pods "$@" -o json) || { echo "kubectl get pods failed" >&2; exit 1; }
printf '%s' "$pods" | jq -c '{
  results: [
    .items[] as $pod
    | (($pod.status.containerStatuses // [])[]
       | select((.lastState.terminated.reason // "") == "OOMKilled")
       | {
           name: $pod.metadata.name,
           namespace: $pod.metadata.namespace,
           container: .name,
           restart_count: (.restartCount // 0)
         })
  ]
}' || { echo "jq failed" >&2; exit 1; }
